import{Z as e}from"./ui-vendor-BC3IF9Zn.js";import{L as i}from"./LegalLayout-CDPaeSqB.js";import"./react-vendor-BBIu9AcQ.js";import"./supabase-vendor-Btrk44BY.js";import"./index-5GMi_xEi.js";import"./chevron-left-Bm-2o1zh.js";function l(){return e.jsxs(i,{docKey:"dsa-compliance",children:[e.jsx("h1",{children:"DSA Compliance & Transparency"}),e.jsx("p",{className:"text-sm text-muted-foreground",children:"RouteMarket.io — Last updated: April 03, 2026"}),e.jsx("p",{children:'This page describes how RouteMarket.io complies with the Digital Services Act (Regulation (EU) 2022/2065, "DSA"), which establishes a framework for the responsibilities of online intermediary services in the European Union. RouteMarket.io qualifies as an "online platform" (Art. 3(i)) and an "online marketplace" (Art. 3(n)) under the DSA.'}),e.jsx("h2",{children:"1. Point of Contact (DSA Art. 11-12)"}),e.jsx("h3",{children:"1.1 Single Point of Contact for Authorities (Art. 11)"}),e.jsx("p",{children:"RouteMarket.io designates the following as its single point of contact for communication with EU Member State authorities, the European Commission, and the European Board for Digital Services:"}),e.jsxs("ul",{children:[e.jsx("li",{children:"Name: Dawid Majka"}),e.jsxs("li",{children:["Email: ",e.jsx("a",{href:"mailto:dsa@routemarket.io",children:"dsa@routemarket.io"})," (or ",e.jsx("a",{href:"mailto:contact@routemarket.io",children:"contact@routemarket.io"}),")"]}),e.jsx("li",{children:"Address: ul. Czeresniowa 67/2, Medlow, 55-020, Poland"}),e.jsx("li",{children:"Languages: English, Polish"})]}),e.jsx("h3",{children:"1.2 Point of Contact for Users (Art. 12)"}),e.jsxs("p",{children:["Users can contact us regarding any DSA-related matter at: ",e.jsx("a",{href:"mailto:contact@routemarket.io",children:"contact@routemarket.io"}),". We offer communication in English and Polish."]}),e.jsx("h2",{children:"2. Legal Representative (DSA Art. 13)"}),e.jsx("p",{children:"As RouteMarket.io is established in Poland (an EU Member State), the designation of a legal representative under Art. 13 is not required. Our legal seat is in Poland and we are directly subject to the jurisdiction of Polish authorities and the European Commission."}),e.jsx("h2",{children:"3. Terms of Service and Content Policies (DSA Art. 14)"}),e.jsx("p",{children:"In accordance with DSA Art. 14, our Terms of Service clearly describe:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:["Content restrictions and the types of content prohibited on the Platform (see ",e.jsx("a",{href:"/legal/acceptable-use",children:"Acceptable Use Policy"}),")."]}),e.jsx("li",{children:"Our content moderation practices, including human review of reports."}),e.jsx("li",{children:"Our internal complaint-handling system for users affected by moderation decisions."}),e.jsxs("li",{children:["The right of users to access out-of-court dispute settlement (see ",e.jsx("a",{href:"/legal/terms",children:"Terms of Service"}),", Section 7.2)."]}),e.jsx("li",{children:"Information about any algorithmic recommendation systems used on the Platform."})]}),e.jsx("p",{children:"These terms are drafted in clear and unambiguous language, and are available in English. We provide plain-language summaries of key provisions to ensure accessibility."}),e.jsx("h2",{children:"4. Transparency Reporting (DSA Art. 15)"}),e.jsx("p",{children:"RouteMarket.io publishes an annual transparency report as required by DSA Art. 15. Starting from 2025, reports follow the standardized templates prescribed by the European Commission's Implementing Regulation (applicable from July 1, 2025)."}),e.jsx("p",{children:"The transparency report includes:"}),e.jsxs("ul",{children:[e.jsx("li",{children:"The number of content removal orders received from EU Member State authorities."}),e.jsx("li",{children:"The number of notices submitted through our notice-and-action mechanism."}),e.jsx("li",{children:"Content moderation activities undertaken at our own initiative."}),e.jsx("li",{children:"The number of complaints received through our internal complaint-handling system."}),e.jsx("li",{children:"The use of automated tools in content moderation (if any)."}),e.jsx("li",{children:"The number of out-of-court dispute settlements and their outcomes."})]}),e.jsx("p",{children:"The most recent transparency report is available for download below. Reports are published annually by February 28 of the following year."}),e.jsx("h2",{children:"5. Notice-and-Action Mechanism (DSA Art. 16)"}),e.jsx("h3",{children:"5.1 How to Submit a Notice"}),e.jsxs("ul",{children:[e.jsx("li",{children:'Use the "Report" button on any Route Package listing.'}),e.jsxs("li",{children:["Email ",e.jsx("a",{href:"mailto:contact@routemarket.io",children:"contact@routemarket.io"}),' with the subject "Content Report".']})]}),e.jsx("h3",{children:"5.2 What to Include"}),e.jsxs("ul",{children:[e.jsx("li",{children:"A sufficiently substantiated explanation of why you consider the content illegal."}),e.jsx("li",{children:"A clear indication of the exact location of the content (URL or listing ID)."}),e.jsx("li",{children:"Your name and email address."}),e.jsx("li",{children:"A declaration of good faith that the information is accurate and complete."})]}),e.jsx("h3",{children:"5.3 How We Process Notices"}),e.jsx("p",{children:"We process all notices in a timely, diligent, non-arbitrary, and objective manner. We will: (a) confirm receipt without undue delay; (b) assess whether the reported content is indeed illegal or violates our policies; (c) take appropriate action (removal, restriction, or no action); (d) inform the reporting person and the affected user of our decision, including a clear statement of reasons (Art. 17)."}),e.jsx("h2",{children:"6. Statement of Reasons (DSA Art. 17)"}),e.jsx("p",{children:"When we restrict, remove, or suspend content or accounts, we provide all affected users with a clear and specific statement of reasons, including:"}),e.jsxs("ul",{children:[e.jsx("li",{children:"The specific content or behavior affected."}),e.jsx("li",{children:"The facts and circumstances relied upon."}),e.jsx("li",{children:"The legal or policy basis for the decision."}),e.jsx("li",{children:"Information about available remedies (internal complaint, out-of-court settlement)."})]}),e.jsx("h2",{children:"7. Internal Complaint-Handling System (DSA Art. 20)"}),e.jsx("p",{children:"Users affected by content moderation decisions (including content removal, account restrictions, or rejection of a report) may lodge a complaint through our internal system:"}),e.jsxs("ul",{children:[e.jsxs("li",{children:["Email: ",e.jsx("a",{href:"mailto:contact@routemarket.io",children:"contact@routemarket.io"}),' (Subject: "DSA Complaint")']}),e.jsx("li",{children:"Deadline: Within 6 months of the moderation decision."})]}),e.jsx("p",{children:"Our commitment:"}),e.jsxs("ul",{children:[e.jsx("li",{children:"Free of charge."}),e.jsx("li",{children:"Handled by qualified personnel not involved in the original decision."}),e.jsx("li",{children:"Processed in a timely, non-discriminatory, and diligent manner."}),e.jsx("li",{children:"Decision communicated to the complainant without undue delay."}),e.jsx("li",{children:"If the original decision is reversed, we will implement the reversal without delay."})]}),e.jsx("h2",{children:"8. Out-of-Court Dispute Settlement (DSA Art. 21)"}),e.jsx("p",{children:"If you are not satisfied with the outcome of our internal complaint-handling process, you have the right to seek out-of-court dispute settlement through a certified body. We will engage in good faith with any such body selected by the user. Information about certified dispute settlement bodies will be provided in our statement of reasons and is available from the Digital Services Coordinator in your Member State."}),e.jsx("h2",{children:"9. Trader Verification (DSA Art. 30 — KYBC)"}),e.jsx("p",{children:"As an online marketplace, RouteMarket.io collects and verifies the following information from all Creators (traders) before allowing them to sell Route Packages:"}),e.jsxs("ul",{children:[e.jsx("li",{children:"Full legal name and any relevant trade name."}),e.jsx("li",{children:"Address, telephone, and email address."}),e.jsx("li",{children:"Copy of identification document."}),e.jsx("li",{children:"Bank account or other payment account details."}),e.jsx("li",{children:"Trade register or equivalent registration (where applicable)."}),e.jsx("li",{children:"Self-certification committing to only offer products compliant with EU law."})]}),e.jsx("p",{children:"We make best efforts to verify this information through our payment provider (Stripe Connect) and by cross-checking publicly available databases where possible. If verification fails or information becomes outdated, we suspend the Creator's ability to sell until re-verification is completed."}),e.jsx("h2",{children:"10. Consumer Information on Listings (DSA Art. 31-32)"}),e.jsx("p",{children:"Each Route Package listing on the Platform clearly displays:"}),e.jsxs("ul",{children:[e.jsx("li",{children:"(a) the Creator's display name;"}),e.jsx("li",{children:"(b) whether the Creator is a professional trader or private individual;"}),e.jsx("li",{children:"(c) that RouteMarket.io is the marketplace and not the seller of the Route Package;"}),e.jsx("li",{children:"(d) applicable consumer rights (refund policy, complaint options);"}),e.jsx("li",{children:"(e) who is responsible for contract performance and after-sales support."})]}),e.jsx("h2",{children:"11. Algorithmic Recommendations"}),e.jsx("p",{children:"RouteMarket.io may use algorithmic systems to recommend Route Packages on the homepage, search results, and category pages. These recommendations are based on: route category, user location preferences, popularity (sales and ratings), and recency. We do not use profiling based on sensitive personal data for recommendations. Users can adjust their recommendation preferences in account settings."}),e.jsx("h2",{children:"12. Digital Services Coordinator"}),e.jsxs("p",{children:["As RouteMarket.io is established in Poland, the competent Digital Services Coordinator is the Polish authority designated under the DSA. At the time of writing, this role is fulfilled by the Office of Electronic Communications (Urząd Komunikacji Elektronicznej, UKE). Website: ",e.jsx("a",{href:"https://uke.gov.pl",target:"_blank",rel:"noopener noreferrer",children:"uke.gov.pl"}),"."]})]})}export{l as default};
